import 'package:flutter/material.dart';
import '../services/api_service.dart';

class CertificateScreen extends StatelessWidget {
  final int courseId; const CertificateScreen({super.key,required this.courseId});
  @override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('Certificate'),actions:[IconButton(tooltip:'Print',onPressed:()=>ScaffoldMessenger.of(context).showSnackBar(const SnackBar(content:Text('Use your browser Print menu to save this certificate as PDF.'))),icon:const Icon(Icons.print))]),body:FutureBuilder<Map<String,dynamic>>(future:ApiService().getCertificate(courseId),builder:(context,s){if(s.connectionState!=ConnectionState.done)return const Center(child:CircularProgressIndicator());if(s.hasError)return Center(child:Text('Certificate unavailable: ${s.error}'));final d=s.data!;return Center(child:AspectRatio(aspectRatio:1.414,child:Card(margin:const EdgeInsets.all(32),shape:RoundedRectangleBorder(side:BorderSide(color:Theme.of(context).colorScheme.primary,width:4),borderRadius:BorderRadius.circular(4)),child:Padding(padding:const EdgeInsets.all(42),child:Column(mainAxisAlignment:MainAxisAlignment.spaceAround,children:[Text(d['title'].toString(),style:Theme.of(context).textTheme.headlineLarge,textAlign:TextAlign.center),Text(d['subtitle'].toString(),style:Theme.of(context).textTheme.titleLarge),Text(d['presentation_text'].toString()),Text(d['recipient_name'].toString(),style:Theme.of(context).textTheme.headlineMedium?.copyWith(fontWeight:FontWeight.bold)),Text('${d['body_text']}\n${d['course_title']}',textAlign:TextAlign.center),Column(children:[Text(d['signatory'].toString(),style:const TextStyle(fontWeight:FontWeight.bold)),Text(d['signatory_title'].toString())])]))));}));
}
